SELECT * FROM ( SELECT ROWNUM AS RNUM , T1.* FROM ( SELECT B.BOARD_NO, B.USER_NO, B.BOARD_TITLE , U.USER_NAME , B.READ_COUNT AS readCount, B.POST_DATE AS postDate, C.GAME_CODE, C.CATEGORY_NAME, (SELECT COUNT(*) FROM BOARD_LIKES L WHERE L.BOARD_NO = B.BOARD_NO) AS likeCount, (SELECT COUNT(*) FROM REPLY R WHERE R.BOARD_NO = B.BOARD_NO AND R.STATUS = 'Y') AS replyCount, (SELECT FILE_PATH || CHANGE_NAME FROM ATTACH_FILE F WHERE F.BOARD_NO = B.BOARD_NO AND ROWNUM = 1) AS thumbnail, ROW_NUMBER() OVER (ORDER BY B.BOARD_NO ASC) AS dispNo FROM BOARD B LEFT JOIN LOG_GG_USER U ON B.USER_NO = U.USER_NO JOIN CATEGORY_TABLE C ON B.CATEGORY_NO = C.CATEGORY_NO WHERE BOARD_CD = 'Y' AND C.GAME_CODE = #{gameCode}
AND B.CATEGORY_NO = #{categoryNo}
ORDER BY B.BOARD_NO DESC) T1 ) WHERE RNUM BETWEEN #{offset} AND #{limit}

